    def product_filter(table, prodList, gs_omit=True):
        mask = np.full(len(table), False)
        gs_text = '_gs-'
        for r in table:
            mk = False
            fileName = r['productFilename']
            for p in prodList:
                if p in fileName:
                    mk = mk | True
                    if gs_text in fileName:
                        mk = not gs_omit

            mask[r.index] = mk
        return mask

